// // This module implements a 4-bit shift register with serial input and parallel output. The shift register shifts its contents to the left on each clock cycle and discards the new serial input.
module shift_register(
    input                 clk,
    input                 rst,
    input                 serial_in,

    output reg [3:0]      parallel_out
);

// Shift register implementation
always @(posedge clk) begin
    if (rst) begin
        parallel_out <= 4'd0;
    end
    else begin
        parallel_out <= {serial_in, parallel_out[3:1]};
    end
end

endmodule
